    /**
     * A default sensitive data filter that masks common sensitive headers.
     */
    public static class DefaultSensitiveDataFilter implements SensitiveDataFilter {
        @Override
        public String filter(String headerName, String value) {
            if (value == null) return "null";

            String lowerName = headerName.toLowerCase(Locale.US);
            if (lowerName.contains("authorization") ||
                lowerName.contains("api-key") ||
                lowerName.contains("api_key") ||
                lowerName.contains("token") ||
                lowerName.contains("secret") ||
                lowerName.contains("password") ||
                lowerName.contains("session")) {

                if (value.length() <= 10) {
                    return "****[" + value.length() + " chars]";
                }
                return value.substring(0, 6) + "****" + value.substring(value.length() - 4) + "[" + value.length() + " chars]";
            }
            return value;
        }
    }

